__kernel void hotspotOpt1(
    __global const float* pIn,
    __global float* tIn,
    __global float* tOut,
    float stepDivCap,
    int nx,
    int ny,
    int nz,
    float ce,
    float cw,
    float cn,
    float cs,
    float ct,
    float cb,
    float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    // Boundary check for the 2D grid dimensions
    if (x >= nx || y >= ny) {
        return;
    }

    // Ambient temperature constant
    const float amb_temp = 80.0f;

    // Iterate over all layers (z dimension) for this (x, y) coordinate
    for (int z = 0; z < nz; z++) {
        // Calculate 1D index
        int c = x + y * nx + z * nx * ny;

        // Calculate neighbor indices with boundary conditions
        int w = (x == 0) ? c : c - 1;
        int e = (x == nx - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - nx;
        int s = (y == ny - 1) ? c : c + nx;
        int b = (z == 0) ? c : c - nx * ny;
        int t = (z == nz - 1) ? c : c + nx * ny;

        // Compute new temperature
        tOut[c] = cc * tIn[c] 
                + cw * tIn[w] 
                + ce * tIn[e] 
                + cs * tIn[s] 
                + cn * tIn[n] 
                + cb * tIn[b] 
                + ct * tIn[t] 
                + stepDivCap * pIn[c] 
                + ct * amb_temp;
    }
}
